provider "aws" {
  alias   = "china"
  region  = "cn-north-1"
  profile = "china-sinnet"
}

# S3 bucket in China — note partition-aware ARN
resource "aws_s3_bucket" "data" {
  provider = aws.china
  bucket   = "my-china-data-bucket"
}

# Use partition data source for portable ARNs
data "aws_partition" "china" {
  provider = aws.china
}

output "bucket_arn" {
  # Produces: arn:aws-cn:s3:::my-china-data-bucket
  value = "arn:${data.aws_partition.china.partition}:s3:::${aws_s3_bucket.data.bucket}"
}

# Create CloudFront distribution in China (requires ICP number)
aws --profile china-sinnet cloudfront create-distribution \
  --distribution-config '{
    "CallerReference": "china-cdn-001",
    "Comment": "China CDN - ICP: 京ICP备12345678号",
    "DefaultCacheBehavior": {
      "TargetOriginId": "s3-origin",
      "ViewerProtocolPolicy": "redirect-to-https",
      "CachePolicyId": "658327ea-f89d-4fab-a63d-7e88639e58f6"
    },
    "Origins": {
      "Quantity": 1,
      "Items": [{
        "Id": "s3-origin",
        "DomainName": "my-bucket.s3.cn-north-1.amazonaws.com.cn"
      }]
    },
    "Enabled": true
  }'

# Create S3 bucket in China with encryption
aws --profile china-sinnet s3api create-bucket \
  --bucket my-china-prod-bucket \
  --region cn-north-1 \
  --create-bucket-configuration LocationConstraint=cn-north-1

# Enable default encryption
aws --profile china-sinnet s3api put-bucket-encryption \
  --bucket my-china-prod-bucket \
  --server-side-encryption-configuration '{
    "Rules": [{"ApplyServerSideEncryptionByDefault": {
      "SSEAlgorithm": "aws:kms",
      "KMSMasterKeyID": "arn:aws-cn:kms:cn-north-1:123456789012:key/abc-123"
    }}]
  }'

# Cross-region replication within China
aws --profile china-sinnet s3api put-bucket-replication \
  --bucket my-china-prod-bucket \
  --replication-configuration '{
    "Role": "arn:aws-cn:iam::123456789012:role/S3ReplicationRole",
    "Rules": [{"Status": "Enabled", "Destination": {
      "Bucket": "arn:aws-cn:s3:::my-china-dr-bucket"
    }}]
  }'
